2925	// =================== Generic CSV export for list tables ===================
2926	// _csvDownload now imported from ./app/util.js (audit A47).
2927	// Visible column headers (skipping the trailing actions/blank column).
2928	function _visibleHeaders(table) {
2929	  const ths = [...table.querySelectorAll("thead th")];
2930	  const keep = ths.map((th) => th.textContent.trim() !== "");
2931	  return { keep, headers: ths.filter((_, i) => keep[i]).map((th) => th.textContent.trim()) };
2932	}
2933	function exportTable(table, name) {
2934	  const { keep, headers } = _visibleHeaders(table);
2935	  const rows = [...table.querySelectorAll("tbody tr")]
2936	    .filter((tr) => !tr.querySelector(".empty"))
2937	    .map((tr) => [...tr.children].filter((_, i) => keep[i]).map((td) => td.textContent.replace(/\s+/g, " ").trim()));
2938	  _csvDownload([headers, ...rows], name);
2939	}
