2961	// =================== Workspace add-forms as modal overlays (grid stays primary) ===================
2962	// Each add-form becomes a centered modal opened by a "＋ Add X" button; the grid
2963	// owns the page. Closing is driven by the form's `reset` event — every submit
2964	// handler resets on success and the Cancel button resets too, so success and
2965	// cancel both close the overlay while a validation error keeps it open.
2966	const FORM_MODALS = {
2967	  "withdrawal-form": "Add withdrawal",
2968	  "sched-form": "Add scheduling avoidance", "divflex-form": "Add division flexibility",
2969	  "pairing-form": "Add pairing group", "doubles-form": "File doubles request",
2970	  "photel-form": "Add player hotel", "late-form": "Add late entry", "trb-form": "Add room block",
2971	  "asg-form": "Assign official", "email-form": "Add email",
2972	};
2973	for (const [id, label] of Object.entries(FORM_MODALS)) {
2974	  const form = document.getElementById(id);
2975	  if (!form || form.closest(".detail-pane")) continue;
2976	  const trigger = document.createElement("button");
2977	  trigger.type = "button"; trigger.className = "new-btn add-trigger"; trigger.textContent = "＋ " + label;
2978	  const modal = document.createElement("div"); modal.className = "detail-pane form-modal";
2979	  const close = document.createElement("button"); close.type = "button"; close.className = "detail-close"; close.textContent = "×"; close.title = "Close";
2980	  const heading = document.createElement("h3"); heading.className = "detail-title"; heading.textContent = label;
2981	  form.parentNode.insertBefore(trigger, form);
2982	  form.parentNode.insertBefore(modal, form);
2983	  modal.append(close, heading, form);
2984	  const openM = () => { modal.classList.add("detail-open"); _detailBackdrop.classList.add("show"); _closeOpenDetail = closeM; scheduleComboSync(); };
2985	  const closeM = () => {
2986	    modal.classList.remove("detail-open"); _detailBackdrop.classList.remove("show"); _closeOpenDetail = null;
2987	    // If this open was a file-from-email flow, return to the Inbox so the user
2988	    // can process the next email without an extra trip back.
2989	    if (form._wasFiling) {
2990	      form._wasFiling = false;
2991	      const inboxTab = document.querySelector('.tab[data-target="panel-t-inbox"]');
2992	      if (inboxTab) inboxTab.click();
2993	    }
2994	  };
2995	  trigger.addEventListener("click", () => { form._wasFiling = false; openM(); });
2996	  close.addEventListener("click", closeM);
2997	  form.addEventListener("reset", closeM);  // success path and Cancel both reset → close
2998	  form._openModal = openM;                  // openForm() (file-from-email) opens it
2999	}

