2317	  let group, rest;
2318	  if (/^(youth|yth|junior|jr)/.test(s) || (s[0] === "y" && s.length <= 4)) {
2319	    group = "Y"; rest = s.replace(/^(youth|yth|junior|jr|y)/, "");
2320	  } else if (/^adult/.test(s) || (s[0] === "a" && s.length <= 4)) {
2321	    group = "A"; rest = s.replace(/^(adult|a)/, "");
2322	  } else { group = "A"; rest = s; }
2323	  const sz = _SIZE_TOKEN[rest];
